	// mm: can member insert record?
	$arrPerm = getTablePermissions('approval_table');
	if(!$arrPerm['insert']) {
		$error_message = $Translation['no insert permission'];
		return false;
	}

	$data = [
		'approval_from' => Request::val('approval_from', 'PD'),
		'type' => Request::val('type', ''),
		'description' => br2nl(Request::val('description', '')),
		'quantity' => Request::val('quantity', ''),
		'full_est_value' => Request::val('full_est_value', ''),
		'name_of_vendor' => br2nl(Request::val('name_of_vendor', '')),
		'purpose' => br2nl(Request::val('purpose', '')),
		'requested_department' => Request::val('requested_department', ''),
		'person_responsbility' => Request::lookup('person_responsbility', ''),
		'mode_of_purchase' => Request::val('mode_of_purchase', ''),
		'others_if_any' => br2nl(Request::val('others_if_any', '')),
		'recurring_budget' => Request::val('recurring_budget', ''),
		'non_recurring_budget' => Request::val('non_recurring_budget', ''),
		'approval_status' => Request::val('approval_status', 'Under Consideration'),
		'remarks_for_approval' => Request::val('remarks_for_approval', 'None'),
		'image' => Request::fileUpload('image', [
			'maxSize' => 1024000,
			'types' => 'jpg|jpeg|gif|png|webp',
			'noRename' => false,
			'dir' => '',
			'success' => function($name, $selected_id) {
				Thumbnail::create($name, getThumbnailSpecs('approval_table', 'image', 'tv'));
				Thumbnail::create($name, getThumbnailSpecs('approval_table', 'image', 'dv'));
			},
			'failure' => function($selected_id, $fileRemoved) {
				if(!strlen(Request::val('SelectedID'))) return '';

				/* for empty upload fields, when saving a copy of an existing record, copy the original upload field */
				return existing_value('approval_table', 'image', Request::val('SelectedID'));
			},
		]),
		'other_file' => Request::fileUpload('other_file', [
			'maxSize' => 102400000,
			'types' => 'txt|doc|docx|docm|odt|pdf|rtf',
			'noRename' => false,
			'dir' => '',
			'success' => function($name, $selected_id) {
			},
			'failure' => function($selected_id, $fileRemoved) {
				if(!strlen(Request::val('SelectedID'))) return '';

				/* for empty upload fields, when saving a copy of an existing record, copy the original upload field */
				return existing_value('approval_table', 'other_file', Request::val('SelectedID'));
			},
		]),
		'created_at' => parseCode('<%%creationDateTime%%>', true),
		'created_by' => parseCode('<%%creatorUsername%%>', true),
	];

	// record owner is current user
	$recordOwner = getLoggedMemberID();

	$recID = tableInsert('approval_table', $data, $recordOwner, $error_message);

	// if this record is a copy of another record, copy children if applicable
	if(strlen(Request::val('SelectedID')) && $recID !== false)
		approval_table_copy_children($recID, Request::val('SelectedID'));

	return $recID;
}

